for type_code, texts in replacements.items():
    # Find the section for this type
    pattern = re.compile(r"(## vs \[" + type_code + r"\].*?)(?=## vs \[|\Z)", re.DOTALL)
    match = pattern.search(content)
    if match:
        section = match.group(1)
        
        # Replace 相性解説
        section = re.sub(r"(### 相性解説\n\n).*?(?=\n### 一緒に楽しむコツ)", r"\1" + texts["相性解説"], section, flags=re.DOTALL)
        
        # Replace 一緒に楽しむコツ
        section = re.sub(r"(### 一緒に楽しむコツ\n\n).*?(?=\n### 摩擦ポイント)", r"\1" + texts["一緒に楽しむコツ"] + "\n", section, flags=re.DOTALL)
        
        # Replace 摩擦ポイント
        section = re.sub(r"(### 摩擦ポイント\n\n).*?(?=\n### 目的の持ち方)", r"\1" + texts["摩擦ポイント"] + "\n", section, flags=re.DOTALL)
        
        content = content[:match.start()] + section + content[match.end():]

